}

// RegisterUser creates a new user profile and inserts it into the database.
func RegisterUser(o orm.Ormer, username, displayName, email, department, role string) (*UserProfile, error) {
	user := &UserProfile{
		Username:    username,
		DisplayName: displayName,
		Email:       email,
		Department:  department,
		Role:        role,
	}
	_, err := o.Insert(user)
	if err != nil {
		return nil, err
	}
	return user, nil
}

// GenerateUserActivityReport creates an activity report for specified users.
func GenerateUserActivityReport(o orm.Ormer, usernames []string, actionTypeFilter string, startDate, endDate time.Time) ([]UserActivitySummary, error) {
	if len(usernames) == 0 {
		return []UserActivitySummary{}, nil
	}

	// Build the IN clause placeholders
	placeholders := make([]string, len(usernames))
	args := make([]interface{}, 0, len(usernames)+3)
	for i := range usernames {
		placeholders[i] = "?"
		args = append(args, usernames[i])
	}

	var query string
	if actionTypeFilter != "" {
		query = fmt.Sprintf(`
			SELECT u.display_name, a.action_type, COUNT(*) as total, 
			       SUM(CASE WHEN a.success THEN 1 ELSE 0 END) as success_count, 
			       AVG(a.duration_ms) as avg_duration
			FROM user_activity a 
			JOIN user_profile u ON a.user_id = u.id
			WHERE u.username IN (%s) AND a.created_at BETWEEN ? AND ? AND a.action_type = ?
			GROUP BY u.display_name, a.action_type`,
			fmt.Sprintf("%s", joinPlaceholders(placeholders)))
		args = append(args, startDate, endDate, actionTypeFilter)
	} else {
		query = fmt.Sprintf(`
			SELECT u.display_name, a.action_type, COUNT(*) as total, 
			       SUM(CASE WHEN a.success THEN 1 ELSE 0 END) as success_count, 
			       AVG(a.duration_ms) as avg_duration
			FROM user_activity a 
			JOIN user_profile u ON a.user_id = u.id
			WHERE u.username IN (%s) AND a.created_at BETWEEN ? AND ?
			GROUP BY u.display_name, a.action_type`,
			fmt.Sprintf("%s", joinPlaceholders(placeholders)))
		args = append(args, startDate, endDate)
	}

	var results []struct {
		DisplayName  string  `orm:"display_name"`
		ActionType   string  `orm:"action_type"`
		Total        int64   `orm:"total"`
		SuccessCount int64   `orm:"success_count"`
		AvgDuration  float64 `orm:"avg_duration"`
	}

	_, err := o.Raw(query, args...).QueryRows(&results)
	if err != nil {
		return nil, err
	}

	summaries := make([]UserActivitySummary, len(results))
	for i, r := range results {
		summaries[i] = UserActivitySummary{
			DisplayName:  r.DisplayName,
			ActionType:   r.ActionType,
			TotalActions: int(r.Total),
			SuccessCount: int(r.SuccessCount),
			AvgDuration:  r.AvgDuration,
		}
	}

	return summaries, nil
}

func joinPlaceholders(placeholders []string) string {
	result := ""
	for i, p := range placeholders {
		if i > 0 {
			result += ", "
		}
		result += p
	}
	return result
}

// GenerateDepartmentReport creates a summary report grouped by a specified field.
func GenerateDepartmentReport(o orm.Ormer, departments []string, groupByField string) ([]map[string]interface{}, error) {
	if len(departments) == 0 {
		return []map[string]interface{}{}, nil
	}

	// Validate groupByField
	validFields := map[string]string{
		"department":   "u.department",
		"role":         "u.role",
		"display_name": "u.display_name",
	}
	fieldExpr, ok := validFields[groupByField]
	if !ok {
		return nil, fmt.Errorf("invalid groupByField: %s", groupByField)
	}

	// Build the IN clause placeholders
	placeholders := make([]string, len(departments))
	args := make([]interface{}, 0, len(departments))
	for i := range departments {
		placeholders[i] = "?"
		args = append(args, departments[i])
	}

	query := fmt.Sprintf(`
		SELECT %s as group_value, COUNT(DISTINCT u.id) as user_count, COUNT(a.id) as total_activities
		FROM user_profile u
		LEFT JOIN user_activity a ON u.id = a.user_id
		WHERE u.department IN (%s)
		GROUP BY %s`,
		fieldExpr,
		joinPlaceholders(placeholders),
		fieldExpr)

	type Result struct {
		GroupValue      string `orm:"group_value"`
		UserCount       int64  `orm:"user_count"`
		TotalActivities int64  `orm:"total_activities"`
	}

	var results []Result
	_, err := o.Raw(query, args...).QueryRows(&results)
	if err != nil {
		return nil, err
	}

	output := make([]map[string]interface{}, len(results))
	for i, r := range results {
		output[i] = map[string]interface{}{
			"group_value":      r.GroupValue,
			"user_count":       int(r.UserCount),
			"total_activities": int(r.TotalActivities),
		}
	}

	return output, nil
}

