			       SUM(CASE WHEN a.success THEN 1 ELSE 0 END) as success_count, 
			       AVG(a.duration_ms) as avg_duration
			FROM user_activity a 
			JOIN user_profile u ON a.user_id = u.id
			WHERE u.username IN (%s) AND a.created_at BETWEEN ? AND ?
			GROUP BY u.display_name, a.action_type`,
			fmt.Sprintf("%s", joinPlaceholders(placeholders)))
	}

	var results []struct {
		DisplayName  string  `orm:"display_name"`
		ActionType   string  `orm:"action_type"`
		Total        int64   `orm:"total"`
		SuccessCount int64   `orm:"success_count"`
